import React from "react";

const githubIcon = "https://cdn.jsdelivr.net/npm/simple-icons@v9/icons/github.svg";

const GlassProjectCard = ({
  title = "Courier Order Booking System",
  description = "A full-stack courier booking app — users book parcels, enter sender & receiver details, select delivery type, and track order status in real time.",
  techStack = ["React", "Express.js", "MongoDB"],
  githubUrl = "https://github.com/",
  status = "Live project",
}) => {
  const techColors = {
    React:      { bg: "rgba(97,218,251,0.1)",  border: "rgba(97,218,251,0.3)",  color: "rgba(97,218,251,0.85)" },
    "Express.js":{ bg: "rgba(255,255,255,0.07)", border: "rgba(255,255,255,0.18)", color: "rgba(255,255,255,0.6)" },
    MongoDB:    { bg: "rgba(0,237,100,0.09)",  border: "rgba(0,237,100,0.25)",  color: "rgba(0,237,100,0.75)" },
  };

  const defaultTech = { bg: "rgba(255,255,255,0.07)", border: "rgba(255,255,255,0.18)", color: "rgba(255,255,255,0.6)" };

  return (
    <>
      <style>{`
        .glass-scene {
          min-height: 380px;
          display: flex;
          align-items: center;
          justify-content: center;
          padding: 2rem;
          background: linear-gradient(135deg, #0a0a0f 0%, #0f1a2e 40%, #0a1628 100%);
          border-radius: 20px;
          position: relative;
          overflow: hidden;
        }
        .glow-orb {
          position: absolute;
          border-radius: 50%;
          filter: blur(60px);
          pointer-events: none;
        }
        .orb1 { width: 280px; height: 280px; background: rgba(35,206,107,0.12); top: -60px; right: -40px; }
        .orb2 { width: 220px; height: 220px; background: rgba(0,120,255,0.10); bottom: -40px; left: 20px; }
        .orb3 { width: 140px; height: 140px; background: rgba(35,206,107,0.07); top: 50%; left: 50%; transform: translate(-50%,-50%); }

        .glass-card {
          width: 320px;
          border-radius: 24px;
          border: 0.5px solid rgba(255,255,255,0.18);
          background: rgba(255,255,255,0.06);
          backdrop-filter: blur(28px) saturate(1.4);
          -webkit-backdrop-filter: blur(28px) saturate(1.4);
          padding: 22px;
          position: relative;
          box-shadow:
            0 2px 0 rgba(255,255,255,0.08) inset,
            0 -1px 0 rgba(0,0,0,0.3) inset,
            0 32px 64px rgba(0,0,0,0.5),
            0 8px 24px rgba(0,0,0,0.3);
          font-family: 'DM Sans', -apple-system, BlinkMacSystemFont, sans-serif;
        }
        .glass-card::before {
          content: '';
          position: absolute;
          top: 0; left: 20px; right: 20px;
          height: 1px;
          background: linear-gradient(90deg, transparent, rgba(255,255,255,0.35), transparent);
          border-radius: 1px;
        }
        .card-header {
          display: flex;
          align-items: center;
          justify-content: space-between;
          margin-bottom: 18px;
        }
        .folder-icon-wrap {
          width: 40px; height: 40px;
          border-radius: 10px;
          background: rgba(35,206,107,0.12);
          border: 0.5px solid rgba(35,206,107,0.3);
          display: flex; align-items: center; justify-content: center;
        }
        .github-btn {
          width: 32px; height: 32px;
          border-radius: 8px;
          background: rgba(255,255,255,0.07);
          border: 0.5px solid rgba(255,255,255,0.12);
          display: flex; align-items: center; justify-content: center;
          cursor: pointer;
          transition: background 0.2s;
          text-decoration: none;
        }
        .github-btn:hover { background: rgba(255,255,255,0.13); }
        .card-title {
          font-size: 15px;
          font-weight: 500;
          color: rgba(255,255,255,0.92);
          margin: 0 0 8px 0;
          letter-spacing: -0.2px;
          line-height: 1.3;
        }
        .card-desc {
          font-size: 12.5px;
          color: rgba(255,255,255,0.45);
          line-height: 1.65;
          margin: 0 0 18px 0;
          font-weight: 300;
        }
        .divider {
          height: 0.5px;
          background: rgba(255,255,255,0.08);
          margin-bottom: 16px;
        }
        .tech-list {
          display: flex;
          gap: 7px;
          flex-wrap: wrap;
          list-style: none;
          padding: 0; margin: 0;
        }
        .tech-badge {
          font-size: 11px;
          font-weight: 500;
          padding: 4px 10px;
          border-radius: 20px;
          letter-spacing: 0.2px;
        }
        .status-row {
          display: flex;
          align-items: center;
          margin-top: 14px;
        }
        .status-dot {
          display: inline-block;
          width: 6px; height: 6px;
          border-radius: 50%;
          background: #23ce6b;
          margin-right: 6px;
          box-shadow: 0 0 6px rgba(35,206,107,0.7);
          animation: pulse 2s infinite;
        }
        .status-text {
          font-size: 11px;
          color: rgba(35,206,107,0.7);
          font-weight: 400;
        }
        @keyframes pulse {
          0%, 100% { opacity: 1; box-shadow: 0 0 6px rgba(35,206,107,0.7); }
          50%       { opacity: 0.6; box-shadow: 0 0 10px rgba(35,206,107,0.4); }
        }
      `}</style>

      <div className="glass-scene">
        <div className="glow-orb orb1" />
        <div className="glow-orb orb2" />
        <div className="glow-orb orb3" />

        <div className="glass-card">
          <div className="card-header">
            <div className="folder-icon-wrap">
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none"
                stroke="#23ce6b" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
                <path d="M22 19a2 2 0 0 1-2 2H4a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h5l2 3h9a2 2 0 0 1 2 2z" />
              </svg>
            </div>
            <a className="github-btn" href={githubUrl} target="_blank" rel="noreferrer" aria-label="GitHub">
              <svg width="15" height="15" viewBox="0 0 24 24" fill="rgba(255,255,255,0.75)">
                <path d="M12 0C5.37 0 0 5.37 0 12c0 5.3 3.44 9.8 8.2 11.38.6.11.82-.26.82-.58v-2.03c-3.34.73-4.04-1.61-4.04-1.61-.54-1.38-1.33-1.75-1.33-1.75-1.09-.74.08-.73.08-.73 1.2.08 1.84 1.24 1.84 1.24 1.07 1.83 2.8 1.3 3.49 1 .11-.78.42-1.3.76-1.6-2.67-.3-5.47-1.33-5.47-5.93 0-1.31.47-2.38 1.24-3.22-.13-.3-.54-1.52.12-3.17 0 0 1.01-.32 3.3 1.23a11.5 11.5 0 0 1 3-.4c1.02.01 2.04.14 3 .4 2.28-1.55 3.29-1.23 3.29-1.23.66 1.65.25 2.87.12 3.17.77.84 1.24 1.91 1.24 3.22 0 4.61-2.81 5.63-5.48 5.93.43.37.81 1.1.81 2.22v3.29c0 .32.22.7.83.58C20.57 21.8 24 17.3 24 12c0-6.63-5.37-12-12-12z" />
              </svg>
            </a>
          </div>

          <h3 className="card-title">{title}</h3>
          <p className="card-desc">{description}</p>

          <div className="divider" />

          <ul className="tech-list">
            {techStack.map((tech) => {
              const style = techColors[tech] || defaultTech;
              return (
                <li key={tech} className="tech-badge" style={{
                  background: style.bg,
                  border: `0.5px solid ${style.border}`,
                  color: style.color,
                }}>
                  {tech}
                </li>
              );
            })}
          </ul>

          <div className="status-row">
            <span className="status-dot" />
            <span className="status-text">{status}</span>
          </div>
        </div>
      </div>
    </>
  );
};

export default GlassProjectCard;
